double closestPair(std::vector<Point> const& points) {
    int rank, size;
    MPI_Comm_rank(MPI_COMM_WORLD, &rank);
    MPI_Comm_size(MPI_COMM_WORLD, &size);

    // Broadcast the complete set of points to all ranks
    std::vector<Point> local_points = points;

    if (size == 1) {
        return bruteForceClosestPair(local_points); // Single rank case
    }

    double min_dist = INFINITY;

    // Divide and conquer approach
    int num_points = local_points.size();
    int chunk_size = std::ceil(num_points / size);

    for (int i = rank * chunk_size; i < (rank + 1) * chunk_size && i < num_points; ++i) {
        Point& p = local_points[i];
        // Compare with all points in the next chunk
        if ((rank + 1) < size && (rank + 1) * chunk_size < num_points) {
            for (int j = (rank + 1) * chunk_size; j < std::min((rank + 2) * chunk_size, num_points); ++j) {
                double dist = distance(p, local_points[j]);
                if (dist < min_dist) min_dist = dist;
            }
        }
    }

    // Reduce to find the minimum distance across all ranks
    MPI_Allreduce(MPI_IN_PLACE, &min_dist, 1, MPI_DOUBLE, MPI_MIN, MPI_COMM_WORLD);

    return min_dist;
}

double bruteForceClosestPair(std::vector<Point> const& points) {
    double min_dist = INFINITY;
    for (size_t i = 0; i < points.size(); ++i) {
        for (size_t j = i + 1; j < points.size(); ++j) {
            double dist = distance(points[i], points[j]);
            if (dist < min_dist) min_dist = dist;
        }
    }
    return min_dist;
}

